public class Solution {
    public int minSubsetSumDifference(int[] arr, int n) {
        int sum = 0;
        for (int i = 0; i < n; i++) sum += arr[i];
        boolean[][] dp = new boolean[n][sum + 1];
        for (int i = 0; i <= sum; i++) dp[0][i] = (arr[0] == i);
        for (int i = 1; i < n; i++) {
            for (int j = 0; j <= sum; j++) {
                if (j < arr[i]) dp[i][j] = dp[i - 1][j];
                else dp[i][j] = dp[i - 1][j] || dp[i - 1][j - arr[i]];
            }
        }
        int mini = sum;
        for (int i = 0; i <= sum / 2; i++) {
            if (dp[n - 1][i]) mini = Math.min(mini, sum - 2 * i);
        }
        return mini;
    }
}
public class Main {
    public static void main(String[] args) {
        int[] arr = {1, 2, 3, 4};
        int n = arr.length;
        Solution solver = new Solution();
        System.out.println(solver.minSubsetSumDifference(arr, n));
    }
}

