class Solution:
    def minSubsetSumDifference(self, arr, n):
        sum_val = sum(arr)
        dp = [[False for _ in range(sum_val + 1)] for _ in range(n)]
        for i in range(sum_val + 1):
            dp[0][i] = (arr[0] == i)
        for i in range(1, n):
            for j in range(sum_val + 1):
                if j < arr[i]:
                    dp[i][j] = dp[i - 1][j]
                else:
                    dp[i][j] = dp[i - 1][j] or dp[i - 1][j - arr[i]]
        mini = sum_val
        for i in range(sum_val // 2 + 1):
            if dp[n - 1][i]:
                mini = min(mini, sum_val - 2 * i)
        return mini

if __name__ == '__main__':
    arr = [1, 2, 3, 4]
    n = len(arr)
    solver = Solution()
    print(solver.minSubsetSumDifference(arr, n))

